// Set up item prices for a shopping cart
const itemPrice: number = 25.50;
const taxRate: number = 0.08;
const quantity: number = 3;
// Arithmetic: calculate total before tax
const subtotal: number = itemPrice * quantity;
// Arithmetic: calculate tax amount
const taxAmount: number = subtotal * taxRate;
// Arithmetic: final total
const total: number = subtotal + taxAmount;
// Comparison: check if customer qualifies for free shipping
const freeShippingThreshold: number = 50;
const qualifiesForFreeShipping: boolean = total >= freeShippingThreshold;
console.log('Subtotal:', subtotal, 'Total:', total);
console.log('Free shipping?', qualifiesForFreeShipping);
// Expected: Subtotal: 76.5 Total: 82.62
// Expected: Free shipping? true
